// Lấy toàn bộ danh sách items từ node trước đó
const items = $input.all();
const today = new Date();

// Duyệt qua từng item để tính toán
const results = items.map(item => {
  const data = item.json;

  // 1. Lấy ngày từ cột LastUpdated [cite: 39]
  const lastUpdated = new Date(data['LastUpdated']);

  // Kiểm tra nếu ngày không hợp lệ thì bỏ qua hoặc giữ nguyên giá
  if (isNaN(lastUpdated.getTime())) {
    return {
      json: { ...data, error: "Invalid Date" }
    };
  }

  // 2. Tính số ngày tồn kho [cite: 18]
  const diffTime = Math.abs(today.getTime() - lastUpdated.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // 3. Lấy giá hiện tại và giá sàn [cite: 5, 17]
  const currentPrice = parseFloat(data['CurrentPrice']) || 0;
  const floorPrice = parseFloat(data['FloorPrice']) || 0;
  let newPrice = currentPrice;

  // 4. Áp dụng logic giảm giá Flow 2 [cite: 20, 21]
  if (diffDays > 60) {
    newPrice = currentPrice * 0.8; // Giảm 20% [cite: 21]
  } else if (diffDays > 30) {
    newPrice = currentPrice * 0.9; // Giảm 10% [cite: 20]
  }

  // 5. Kiểm tra an toàn giá sàn [cite: 8]
  if (newPrice < floorPrice) {
    newPrice = floorPrice;
  }

  // Trả về dữ liệu đã xử lý
  return {
    json: {
      ...data,
      calculated_new_price: Math.round(newPrice),
      days_in_stock: diffDays,
      is_discounted: newPrice < currentPrice
    }
  };
});

return results;

const results = {};
const inputItems = $input.all();

for (const item of inputItems) {
  // Sửa thành viết thường theo chuẩn Supabase trong ảnh của bạn
  const email = item.json.email || "no-email@test.com"; 

  if (!results[email]) {
    results[email] = {
      json: {
        Name: item.json.name, // Sửa Name -> name
        Email: email,
        Products: []
      }
    };
  }

  // Lấy tên sản phẩm từ trường product_name (viết thường)
  const pName = item.json.product_name || item.json.sku || "Sản phẩm";

  // Lấy giá từ trường current_price (viết thường)
  const pPrice = item.json.current_price || 0;

  results[email].json.Products.push({
    DisplayName: pName, 
    Price: pPrice
  });
}

return Object.values(results);

// ==================== CODE ĐÃ SỬA LỖI TYPE ====================

const serpData = $("HTTP Request").all()[0]?.json || {};
const properties = serpData.properties || serpData.hotels || serpData.organic_results || [];

const ourRooms = $("Supabase_Get_All_Rooms").all();

return ourRooms.map(room => {
  const roomData = room.json || room;

  // ===== SỬA LỖI TYPE Ở ĐÂY =====
  const myTypeRaw = roomData.room_type || "";
  const myType = String(myTypeRaw).trim();

  const myPriceRaw = roomData.current_price || 1000000;
  const myPrice = typeof myPriceRaw === 'number' 
    ? myPriceRaw 
    : parseInt(String(myPriceRaw)) || 1000000;

  // Mapping từ khóa
  const roomMapping = {
    "Standard Single": ["standard", "single", "tiêu chuẩn", "superior", "classic", "basic"],
    "Deluxe Double": ["deluxe", "double", "superior", "king", "twin", "premium"],
    "Suite Sea View": ["suite", "sea view", "ocean view", "hướng biển", "seafront", "balcony"],
    "Family Room": ["family", "gia đình", "family room", "4 người"]
  };

  const keywords = roomMapping[myType] || [myType.toLowerCase()];

  const competitorPrices = properties
    .filter(h => {
      const title = String(h.title || h.name || h.description || "").toLowerCase();
      if (title.length < 5) return false;

      let score = 0;

      if (title.includes(myType.toLowerCase())) score += 12;

      keywords.forEach(kw => {
        if (title.includes(String(kw).toLowerCase())) score += 7;
      });

      // Fuzzy match
      const myWords = myType.toLowerCase().split(/[\s\-]+/);
      myWords.forEach(word => {
        if (word.length > 3 && title.includes(word)) score += 4;
      });

      // Bonus
      if (myType.includes("Sea") && (title.includes("sea") || title.includes("ocean"))) score += 10;
      if (myType.includes("Suite") && title.includes("suite")) score += 10;
      if (myType.includes("Family") && title.includes("family")) score += 10;
      if (myType.includes("Deluxe") && title.includes("deluxe")) score += 8;

      return score >= 6;
    })
    .map(h => {
      const rate = h.rate_per_night?.lowest || h.price || h.extracted_price || 0;
      return typeof rate === 'string' 
        ? parseInt(rate.replace(/[^0-9]/g, '')) || 0 
        : parseInt(rate) || 0;
    })
    .filter(p => p > 200000);

  const avgMarket = competitorPrices.length > 0 
    ? Math.round(competitorPrices.reduce((a, b) => a + b, 0) / competitorPrices.length)
    : myPrice;

  let decision = "KEEP";
  let newPrice = myPrice;

  if (myPrice > avgMarket * 1.22) {
    decision = "REDUCE";
    newPrice = Math.round(avgMarket * 1.06);
  } else if (myPrice < avgMarket * 0.78) {
    decision = "INCREASE";
    newPrice = Math.round(avgMarket * 0.95);
  }

  return {
    json: {
      room_id: roomData.id,
      room_type: myType,
      old_price: myPrice,
      new_price: newPrice,
      avg_market: avgMarket,
      competitors_found: competitorPrices.length,
      decision: decision,
      analysis_date: new Date().toLocaleString("vi-VN")
    }
  };
});

// Lấy danh sách từ ngăn ads và properties
const properties = $input.first().json.properties || [];

// Gộp lại thành một danh sách phẳng
const allHotels = [ ...properties];

return allHotels.map(hotel => {
  return {
    json: {
      hotel_name: hotel.name,
      // ĐÂY LÀ QUAN TRỌNG NHẤT: Lấy token để node sau đi quét sâu
      property_token: hotel.property_token, 
    }
  };
});

// Chế độ: Run Once For All Items
const allItems = $input.all(); // Lấy tất cả khách sạn từ node trước
let finalResults = [];

// Duyệt qua từng khách sạn (item)
allItems.forEach(item => {
  const hotelDetail = item.json;
  const featuredPrices = hotelDetail.featured_prices || [];
  const realName = hotelDetail.properties?.name || hotelDetail.name || "Unknown Hotel";

  // Duyệt qua từng giá phòng trong khách sạn đó
  featuredPrices.forEach(priceItem => {
    const rooms = priceItem.rooms || [];

    rooms.forEach(room => {
      finalResults.push({
        json: {
          hotel_name: realName,
          room_name: room.name,
          price: priceItem.rate_per_night?.extracted_lowest || 0,
          source: priceItem.source,
          beds: room.beds?.map(b => `${b.count} ${b.type}`).join(", ") || "N/A"
        }
      });
    });
  });
});

return finalResults;

const allData = $input.all();

const myRooms = allData.filter(item => item.json.room_type);
const competitorRooms = allData.filter(item => item.json.hotel_name);

// Tính giá sàn trung bình của toàn bộ khu vực để làm phương án dự phòng (Fallback)
const allRivalPrices = competitorRooms.map(r => Number(r.json.price) || 0).filter(p => p > 0);
const marketMinPrice = allRivalPrices.length > 0 ? Math.min(...allRivalPrices) : 0;

let comparisonResults = [];

myRooms.forEach(myRoom => {
  const myType = (myRoom.json.room_type || '').toLowerCase().trim();
  const myPrice = myRoom.json.current_price || 0;

  const rivals = competitorRooms.filter(r => {
    let rivalName = (r.json.room_name || '').toLowerCase().trim();
    if (!rivalName) return false;

    // === LOGIC MATCHING NÂNG CAO CHO ĐÀ NẴNG ===
    const matchStandard = (myType.includes('standard') || myType.includes('single')) && 
                          (rivalName.includes('standard') || rivalName.includes('đơn') || rivalName.includes('1 giường') || rivalName.includes('tiêu chuẩn'));

    const matchDeluxe = myType.includes('deluxe') && (rivalName.includes('deluxe') || rivalName.includes('sang trọng'));

    const matchSuite = myType.includes('suite') && (rivalName.includes('suite') || rivalName.includes('cao cấp'));

    const matchFamily = (myType.includes('family') || myType.includes('gia đình')) && 
                        (rivalName.includes('family') || rivalName.includes('gia đình') || rivalName.includes('famil') || rivalName.includes('4 người'));

    const matchView = (myType.includes('sea') || myType.includes('view')) && 
                      (rivalName.includes('sea') || rivalName.includes('biển') || rivalName.includes('hướng'));

    return matchStandard || matchDeluxe || matchSuite || matchFamily || matchView || rivalName.includes(myType);
  });

  // Xử lý giá trị khi không tìm thấy phòng trùng khớp
  let minRivalPrice = null;
  let cheapestRivalName = null;
  let status = "";

  if (rivals.length > 0) {
    minRivalPrice = Math.min(...rivals.map(r => Number(r.json.price) || 0));
    const cheapestRival = rivals.find(r => Number(r.json.price) === minRivalPrice);
    cheapestRivalName = cheapestRival ? cheapestRival.json.hotel_name : "N/A";
    status = myPrice > minRivalPrice ? "🔴 Đắt" : "🟢 Tốt";
  } else {
    // Nếu không khớp loại phòng nào, lấy giá thấp nhất thị trường để Sơn tham khảo
    minRivalPrice = marketMinPrice;
    cheapestRivalName = "Toàn thị trường (Giá sàn)";
    status = "🟡 Tham khảo sàn";
  }

  comparisonResults.push({
    json: {
      room_type: myRoom.json.room_type,
      khoi_price: myPrice,
      competitor_min_price: minRivalPrice,
      competitor_name: cheapestRivalName,
      matching_rooms_count: rivals.length,
      status: status
    }
  });
});

return comparisonResults;
